    assertFalse(objectType.hasProperty("x"));
    assertEquals(
        Sets.newHashSet(objectType),
        registry.getTypesWithProperty("x"));
  }

// com.google.javascript.jscomp.TypeCheckTest::testGatherProperyWithoutAnnotation2
